const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeRows(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return [];

    try {
      const parsed = JSON.parse(text);
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }

  return [];
}

const rawAction = safeText(input.action, 'ensureAndWrite').toLowerCase();
let action = 'ensureAndWrite';
if (rawAction === 'ensuresheet') action = 'ensureSheet';
if (rawAction === 'upsertrows') action = 'upsertRows';

const spreadsheetId = safeText(input.spreadsheetId);
const spreadsheetName = safeText(input.spreadsheetName, 'untitled-sheet');
const sheetName = safeText(input.sheetName, 'Sheet1');
const folderId = safeText(input.folderId);
const rows = normalizeRows(input.rows);
const writeRange = safeText(input.range, '');
const upsertByHeader = safeText(input.upsertByHeader);
const failOnNoUpdates = input.failOnNoUpdates === true || safeText(input.failOnNoUpdates).toLowerCase() === 'true';

const normalizedValueInputOption = safeText(input.valueInputOption, 'RAW').toUpperCase();
const valueInputOption = normalizedValueInputOption === 'USER_ENTERED'
  ? 'USER_ENTERED'
  : 'RAW';

const shouldEnsure = action === 'ensureAndWrite' || action === 'ensureSheet';
const shouldWrite = action === 'ensureAndWrite' || action === 'upsertRows';
const shouldMove = shouldEnsure && folderId !== '';
const shouldCreateSheet = shouldEnsure && spreadsheetId === '';
const missingSpreadsheetIdForWrite = shouldWrite && spreadsheetId === '';
const shouldCallWriteApi = shouldWrite && !missingSpreadsheetIdForWrite && rows.length > 0;

return {
  ...input,
  action,
  spreadsheetId,
  spreadsheetName,
  sheetName,
  folderId,
  rows,
  writeRange,
  upsertByHeader,
  failOnNoUpdates,
  valueInputOption,
  shouldEnsure,
  shouldWrite,
  shouldMove,
  shouldCreateSheet,
  missingSpreadsheetIdForWrite,
  shouldCallWriteApi,
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const spreadsheetId = safeText(input.spreadsheetId);
const spreadsheetUrl = spreadsheetId ? 'https://docs.google.com/spreadsheets/d/' + spreadsheetId : '';

return {
  ...input,
  statusCode: spreadsheetId ? 200 : 404,
  body: {
    spreadsheetId,
    spreadsheetUrl,
  },
};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const normalized = $('Normalize Request').item.json || {};

let ensured = {};
try {
  ensured = $('Create Sheet').item.json || {};
} catch (error) {
  ensured = {};
}

if (!ensured || Object.keys(ensured).length === 0) {
  try {
    ensured = $('Use Existing Sheet').item.json || {};
  } catch (error) {
    ensured = {};
  }
}

const body = ensured.body && typeof ensured.body === 'object' ? ensured.body : {};
const spreadsheetId = safeText(body.spreadsheetId, safeText(ensured.spreadsheetId, safeText(normalized.spreadsheetId)));
const spreadsheetUrl = safeText(
  body.spreadsheetUrl,
  safeText(ensured.spreadsheetUrl, spreadsheetId ? 'https://docs.google.com/spreadsheets/d/' + spreadsheetId : ''),
);

const createStatusCodeRaw = Number(ensured.statusCode ?? 0);
const createStatusCode = Number.isFinite(createStatusCodeRaw) ? createStatusCodeRaw : 0;

return {
  ...normalized,
  spreadsheetId,
  spreadsheetUrl,
  createStatusCode,
};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asPositiveInt(value, fallback = 0) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return n > 0 ? Math.floor(n) : fallback;
}

const normalized = $('Normalize Request').item.json || {};
let prepared = {};
try {
  prepared = $('Prepare Sheet Meta').item.json || {};
} catch (error) {
  prepared = {};
}

let writePayload = {};
try {
  writePayload = $('Prepare Write Payload').item.json || {};
} catch (error) {
  writePayload = {};
}

let writeResponse = {};
try {
  writeResponse = $('Write Sheet Rows').item.json || {};
} catch (error) {
  writeResponse = {};
}

let moveExecuted = false;
try {
  const moveResponse = $('Move Sheet To Folder').item.json || {};
  moveExecuted = Object.keys(moveResponse).length >= 0;
} catch (error) {
  moveExecuted = false;
}

const context = {
  ...normalized,
  ...prepared,
  ...writePayload,
};

const spreadsheetId = safeText(context.spreadsheetId);
const spreadsheetUrl = safeText(context.spreadsheetUrl, spreadsheetId ? 'https://docs.google.com/spreadsheets/d/' + spreadsheetId : '');

const createStatusCodeRaw = Number(context.createStatusCode ?? 0);
const createStatusCode = Number.isFinite(createStatusCodeRaw) ? createStatusCodeRaw : 0;

const writeStatusCodeRaw = Number(writeResponse.statusCode ?? 0);
const writeStatusCode = Number.isFinite(writeStatusCodeRaw) ? writeStatusCodeRaw : 0;

const shouldWriteRequested = context.shouldWrite === true;
const shouldWrite = shouldWriteRequested && context.shouldCallWriteApi === true;
const shouldMove = context.shouldMove === true;
const missingSpreadsheetIdForWrite = context.missingSpreadsheetIdForWrite === true;
const inputRowsCount = asPositiveInt(context.inputRowsCount, Array.isArray(context.rows) ? context.rows.length : 0);

const writeBody = writeResponse.body && typeof writeResponse.body === 'object' ? writeResponse.body : {};
const updatedRows = asPositiveInt(writeBody.totalUpdatedRows, 0);
const updatedCells = asPositiveInt(writeBody.totalUpdatedCells, 0);
const failOnNoUpdates = context.failOnNoUpdates === true;
const noOpWrite = shouldWrite && inputRowsCount > 0 && updatedRows === 0 && updatedCells === 0;

if (shouldWrite && missingSpreadsheetIdForWrite) {
  throw new Error('spreadsheetId is required for upsertRows');
}

if (shouldWrite && !(writeStatusCode >= 200 && writeStatusCode < 300)) {
  throw new Error('Google Sheets write failed (statusCode=' + writeStatusCode + ')');
}

if (noOpWrite && failOnNoUpdates) {
  throw new Error('Google Sheets write reported success but updated 0 rows/cells');
}

const writeOk = !shouldWrite || (writeStatusCode >= 200 && writeStatusCode < 300);
const ensureOk = context.shouldEnsure !== true || spreadsheetId !== '';
const moveStatus = shouldMove ? (moveExecuted ? 'success' : 'skipped') : 'skipped';

return {
  ...context,
  status: ensureOk && writeOk ? 'success' : 'partial',
  spreadsheetId,
  spreadsheetUrl,
  createStatusCode,
  writeStatusCode,
  writeRange: safeText(context.writeRangeResolved || context.writeRange),
  moveStatus,
  inputRowsCount,
  updatedRows,
  updatedCells,
  noOpWrite,
};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeRows2D(value) {
  if (!Array.isArray(value)) return [];
  return value.map((row) => {
    if (!Array.isArray(row)) return [];
    return row.map((cell) => String(cell ?? ''));
  });
}

function normalizeHeaderRow(row) {
  if (!Array.isArray(row)) return [];
  return row.map((cell) => safeText(cell));
}

function readExistingRows(response) {
  const body = response && typeof response.body === 'object' ? response.body : {};
  const values = Array.isArray(body.values) ? body.values : [];
  return normalizeRows2D(values);
}

function ensureRowLength(row, length) {
  const normalized = Array.isArray(row) ? [...row] : [];
  while (normalized.length < length) normalized.push('');
  if (normalized.length > length) return normalized.slice(0, length);
  return normalized;
}

function toColumnLetter(index) {
  let n = Number(index);
  let result = '';
  while (n > 0) {
    const mod = (n - 1) % 26;
    result = String.fromCharCode(65 + mod) + result;
    n = Math.floor((n - mod) / 26);
  }
  return result || 'A';
}

function makeRange(sheetName, colStart, rowStart, colEnd = colStart, rowEnd = rowStart) {
  const start = toColumnLetter(colStart) + String(rowStart);
  const end = toColumnLetter(colEnd) + String(rowEnd);
  if (start === end) return sheetName + '!' + start;
  return sheetName + '!' + start + ':' + end;
}

const meta = $('Prepare Sheet Meta').item.json || {};
const readResponse = $json || {};
const existingRows = readExistingRows(readResponse);
const inputRows = normalizeRows2D(meta.rows);
const sheetName = safeText(meta.sheetName, 'Sheet1');
const providedRange = safeText(meta.writeRange, '');
const upsertByHeader = safeText(meta.upsertByHeader, '');

const batchData = [];
let writeRangeResolved = providedRange || (sheetName + '!A1');
let upsertMatched = 0;
let upsertInserted = 0;
let appendedRows = 0;

if (upsertByHeader) {
  if (inputRows.length === 0) {
    throw new Error('rows is required for upsertByHeader mode');
  }

  const inputHeader = normalizeHeaderRow(inputRows[0]);
  if (inputHeader.length === 0) {
    throw new Error('rows[0] header is required for upsertByHeader mode');
  }

  const keyHeader = upsertByHeader;
  const inputKeyIndex = inputHeader.findIndex((h) => h === keyHeader);
  if (inputKeyIndex < 0) {
    throw new Error('upsertByHeader not found in input header: ' + keyHeader);
  }

  const existingHeader = existingRows.length > 0 ? normalizeHeaderRow(existingRows[0]) : [];
  const finalHeader = existingHeader.length > 0 ? [...existingHeader] : [...inputHeader];

  if (existingRows.length === 0) {
    batchData.push({
      range: makeRange(sheetName, 1, 1, finalHeader.length, 1),
      majorDimension: 'ROWS',
      values: [finalHeader],
    });
  }

  const missingHeaders = [];
  for (const header of inputHeader) {
    if (!header) continue;
    if (!finalHeader.includes(header)) {
      finalHeader.push(header);
      missingHeaders.push(header);
    }
  }

  if (missingHeaders.length > 0) {
    const startCol = finalHeader.length - missingHeaders.length + 1;
    const endCol = finalHeader.length;
    batchData.push({
      range: makeRange(sheetName, startCol, 1, endCol, 1),
      majorDimension: 'ROWS',
      values: [missingHeaders],
    });
  }

  const finalKeyIndex = finalHeader.findIndex((h) => h === keyHeader);
  if (finalKeyIndex < 0) {
    throw new Error('upsertByHeader not found in final header: ' + keyHeader);
  }

  const dataRows = (existingRows.length > 0 ? existingRows.slice(1) : [])
    .map((row) => ensureRowLength(row, finalHeader.length));

  const rowIndexByKey = new Map();
  dataRows.forEach((row, index) => {
    const key = safeText(row[finalKeyIndex]);
    if (key && !rowIndexByKey.has(key)) {
      rowIndexByKey.set(key, index);
    }
  });

  let nextSheetRow = existingRows.length > 0 ? existingRows.length + 1 : 2;

  for (const inputRowRaw of inputRows.slice(1)) {
    const inputRow = ensureRowLength(inputRowRaw, inputHeader.length);
    const key = safeText(inputRow[inputKeyIndex]);
    if (!key) continue;

    const mapped = {};
    inputHeader.forEach((header, index) => {
      if (!header) return;
      mapped[header] = String(inputRow[index] ?? '');
    });

    if (rowIndexByKey.has(key)) {
      const dataIndex = rowIndexByKey.get(key);
      const sheetRow = dataIndex + 2;
      for (const header of inputHeader) {
        if (!header || header === keyHeader) continue;
        const col = finalHeader.findIndex((h) => h === header) + 1;
        if (col <= 0) continue;
        batchData.push({
          range: makeRange(sheetName, col, sheetRow),
          majorDimension: 'ROWS',
          values: [[mapped[header] || '']],
        });
      }
      upsertMatched += 1;
      continue;
    }

    const newRow = Array(finalHeader.length).fill('');
    newRow[finalKeyIndex] = key;
    for (const header of inputHeader) {
      if (!header || header === keyHeader) continue;
      const col = finalHeader.findIndex((h) => h === header);
      if (col >= 0) newRow[col] = mapped[header] || '';
    }

    batchData.push({
      range: makeRange(sheetName, 1, nextSheetRow, finalHeader.length, nextSheetRow),
      majorDimension: 'ROWS',
      values: [newRow],
    });

    dataRows.push(newRow);
    rowIndexByKey.set(key, dataRows.length - 1);
    nextSheetRow += 1;
    upsertInserted += 1;
  }

  writeRangeResolved = sheetName + '!A1';
} else {
  if (providedRange) {
    batchData.push({
      range: providedRange,
      majorDimension: 'ROWS',
      values: inputRows,
    });
    writeRangeResolved = providedRange;
  } else {
    let rowsToAppend = inputRows;
    const existingHeader = existingRows.length > 0 ? normalizeHeaderRow(existingRows[0]) : [];
    const inputHeader = inputRows.length > 0 ? normalizeHeaderRow(inputRows[0]) : [];

    const sameHeader = existingHeader.length > 0
      && existingHeader.length === inputHeader.length
      && existingHeader.every((cell, index) => cell === inputHeader[index]);

    if (sameHeader) {
      rowsToAppend = inputRows.slice(1);
    }

    const appendStart = existingRows.length + 1;
    batchData.push({
      range: sheetName + '!A' + String(appendStart),
      majorDimension: 'ROWS',
      values: rowsToAppend,
    });
    writeRangeResolved = sheetName + '!A' + String(appendStart);
    appendedRows = rowsToAppend.length;
  }
}

const inputRowsCount = batchData.reduce((sum, entry) => {
  const values = Array.isArray(entry.values) ? entry.values : [];
  return sum + values.length;
}, 0);

return {
  ...meta,
  writeRangeResolved,
  batchData,
  inputRowsCount,
  upsertMatched,
  upsertInserted,
  appendedRows,
};
